"use client";

import * as React from "react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { useCoarsePointer, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useWebGLStage } from "@/components/experience/use-webgl-stage";

export type FluidSurfaceProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  src: string;
  alt: string;
  strength?: number;
  radius?: number;
  decay?: number;
  chromatic?: number;
  maxDpr?: number;
  children?: React.ReactNode;
  fallback?: React.ReactNode;
  canvasClassName?: string;
};

const VERTEX = /* glsl */ `
  varying vec2 vUv;
  void main() { vUv = uv; gl_Position = vec4(position, 1.); }
`;

const FRAGMENT = /* glsl */ `
  precision highp float;
  varying vec2 vUv;
  uniform sampler2D uTexture;
  uniform vec2 uResolution;
  uniform vec2 uImageSize;
  uniform vec4 uRipples[5];
  uniform float uStrength;
  uniform float uRadius;
  uniform float uChromatic;

  vec2 coverUv(vec2 uv) {
    float screenAspect = uResolution.x / max(1., uResolution.y);
    float imageAspect = uImageSize.x / max(1., uImageSize.y);
    vec2 ratio = vec2(min(screenAspect / imageAspect, 1.), min(imageAspect / screenAspect, 1.));
    return (uv - .5) * ratio + .5;
  }

  void main() {
    vec2 aspect = vec2(uResolution.x / max(1., uResolution.y), 1.);
    vec2 displacement = vec2(0.);
    float highlight = 0.;
    for (int i = 0; i < 5; i++) {
      vec2 d = (vUv - uRipples[i].xy) * aspect;
      float dist = length(d);
      float age = uRipples[i].z;
      float amp = uRipples[i].w * exp(-age * 2.2);
      float wave = sin(dist * 42. - age * 9.) * exp(-dist / max(.01, uRadius)) * amp;
      displacement += normalize(d + vec2(.0001)) * wave * uStrength;
      highlight += abs(wave) * .1;
    }
    vec2 uv = coverUv(vUv - displacement);
    vec2 ca = normalize(displacement + vec2(.0001)) * uChromatic * min(1., length(displacement) * 35.);
    vec3 color;
    color.r = texture2D(uTexture, uv + ca).r;
    color.g = texture2D(uTexture, uv).g;
    color.b = texture2D(uTexture, uv - ca).b;
    color += highlight;
    gl_FragColor = vec4(color, 1.);
  }
`;

/** An image surface with dissipating pointer impulses; it preserves the native cursor. */
export function FluidSurface({
  alt,
  canvasClassName,
  children,
  chromatic = 0.0014,
  className,
  decay = 1,
  fallback,
  label,
  maxDpr = 1.6,
  radius = 0.24,
  src,
  strength = 0.018,
  onPointerMove,
  ...props
}: FluidSurfaceProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const impulsesRef = React.useRef<Array<{ x: number; y: number; age: number; power: number }>>([]);
  const lastPointerRef = React.useRef({ x: 0.5, y: 0.5, time: 0 });
  const reducedMotion = usePrefersReducedMotion();
  const coarsePointer = useCoarsePointer();
  const staticMode = reducedMotion || coarsePointer;

  const { ready, failed } = useWebGLStage({
    stageRef: rootRef,
    canvasRef,
    enabled: !staticMode,
    maxDpr,
    signature: JSON.stringify([chromatic, decay, radius, src, strength]),
    create: ({ renderer, markReady, markFailed, isDisposed, requestResize }) => {
      let texture: THREE.Texture | null = null;
      const scene = new THREE.Scene();
      const camera = new THREE.Camera();
      const geometry = new THREE.PlaneGeometry(2, 2);
      const rippleVectors = Array.from({ length: 5 }, () => new THREE.Vector4(0.5, 0.5, 99, 0));
      const uniforms = {
        uTexture: { value: new THREE.Texture() },
        uResolution: { value: new THREE.Vector2(1, 1) },
        uImageSize: { value: new THREE.Vector2(1, 1) },
        uRipples: { value: rippleVectors },
        uStrength: { value: strength },
        uRadius: { value: radius },
        uChromatic: { value: chromatic },
      };
      const material = new THREE.ShaderMaterial({ vertexShader: VERTEX, fragmentShader: FRAGMENT, uniforms, depthTest: false, depthWrite: false });
      scene.add(new THREE.Mesh(geometry, material));

      new THREE.TextureLoader().load(
        src,
        (loaded) => {
          if (isDisposed()) {
            loaded.dispose();
            return;
          }
          texture = loaded;
          texture.colorSpace = THREE.SRGBColorSpace;
          const image = loaded.image as { width?: number; height?: number };
          uniforms.uTexture.value = loaded;
          uniforms.uImageSize.value.set(image.width ?? 1, image.height ?? 1);
          requestResize();
          markReady();
        },
        undefined,
        () => markFailed(),
      );

      return {
        onResize: (width, height) => {
          uniforms.uResolution.value.set(width, height);
          renderer.render(scene, camera);
        },
        onFrame: (delta) => {
          impulsesRef.current.forEach((impulse) => {
            impulse.age += delta * decay;
          });
          impulsesRef.current = impulsesRef.current.filter((impulse) => impulse.age < 2.6).slice(-5);
          rippleVectors.forEach((vector, index) => {
            const impulse = impulsesRef.current[index];
            vector.set(impulse?.x ?? 0.5, impulse?.y ?? 0.5, impulse?.age ?? 99, impulse?.power ?? 0);
          });
          renderer.render(scene, camera);
        },
        dispose: () => {
          texture?.dispose();
          geometry.dispose();
          material.dispose();
        },
      };
    },
  });

  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => {
    if (event.pointerType !== "touch") {
      const now = performance.now();
      const rect = event.currentTarget.getBoundingClientRect();
      const x = (event.clientX - rect.left) / Math.max(1, rect.width);
      const y = 1 - (event.clientY - rect.top) / Math.max(1, rect.height);
      const previous = lastPointerRef.current;
      if (now - previous.time > 42) {
        const velocity = Math.min(1, Math.hypot(x - previous.x, y - previous.y) * 18 + 0.18);
        impulsesRef.current.push({ x, y, age: 0, power: velocity });
        lastPointerRef.current = { x, y, time: now };
      }
    }
    onPointerMove?.(event);
  };
  const posterStyle = { backgroundImage: `url("${src.replaceAll('"', '%22')}")` };

  return (
    <section ref={rootRef} aria-label={label} data-fluid-surface data-ready={ready || undefined} className={cn("relative isolate overflow-hidden bg-black", className)} onPointerMove={handlePointerMove} {...props}>
      <span className="sr-only">{alt}</span>
      <div aria-hidden className={cn("absolute inset-0 -z-20 bg-cover bg-center", ready && !failed && !staticMode ? "opacity-0" : "opacity-100")} style={posterStyle} />
      <canvas ref={canvasRef} aria-hidden className={cn("absolute inset-0 -z-10 size-full transition-opacity duration-500", ready && !failed && !staticMode ? "opacity-100" : "opacity-0", canvasClassName)} />
      {(failed || staticMode) && fallback ? <div className="absolute inset-0 -z-10">{fallback}</div> : null}
      {children}
    </section>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import * as THREE from "three";

import { supportsWebGL } from "@/components/experience/experience-runtime";

export type WebGLStageContext = {
  renderer: THREE.WebGLRenderer;
  stage: HTMLElement;
  canvas: HTMLCanvasElement;
  /** Flip the stage to ready once async assets are decoded and the first frame can show. */
  markReady: () => void;
  /** Flip the stage to failed (poster/fallback becomes visible). */
  markFailed: () => void;
  /** True after the stage effect has been cleaned up; guard async callbacks with it. */
  isDisposed: () => boolean;
  /** Re-run the resize pass — call after async assets load so size-dependent caps apply. */
  requestResize: () => void;
};

export type WebGLStageHandle = {
  /** Runs every animation frame while the stage is on screen, the tab is visible and the context is alive. */
  onFrame?: (deltaSeconds: number, time: number) => void;
  /** Runs after the renderer resized; update cameras, uniforms and derived scales here. */
  onResize?: (width: number, height: number) => void;
  /** Optional extra cap on device pixel ratio for a given stage size (e.g. never supersample past the source texture). */
  getDpr?: (width: number, height: number) => number;
  /** Dispose geometries, materials and textures created in `create`; the renderer itself is disposed by the hook. */
  dispose?: () => void;
};

export type WebGLStageOptions = {
  stageRef: React.RefObject<HTMLElement | null>;
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
  /** false keeps the stage fully inert — use it for reduced-motion / coarse-pointer static modes. */
  enabled: boolean;
  maxDpr?: number;
  antialias?: boolean;
  alpha?: boolean;
  /** Request a stencil buffer (three defaults it off since r163); needed for aperture/mask scenes. */
  stencil?: boolean;
  /**
   * Serialize every visual prop that must rebuild the scene into this string.
   * Array or callback identity never triggers a rebuild, so inline props stay safe.
   */
  signature?: string;
  /** Root margin for the offscreen pause observer. */
  rootMargin?: string;
  /** Build the scene. Reads props freely (latest values are visible via closure on each rebuild). */
  create: (context: WebGLStageContext) => WebGLStageHandle | void;
};

/**
 * Shared WebGL lifecycle for experience stages: renderer with capped DPR,
 * resize + offscreen observers, a visibility-gated animation loop, context-loss
 * pause with context-restore recovery, and full disposal. Components own only
 * their scene graph and per-frame logic.
 */
export function useWebGLStage({
  alpha = false,
  antialias = false,
  canvasRef,
  create,
  enabled,
  maxDpr = 1.6,
  rootMargin = "20% 0px",
  signature,
  stageRef,
  stencil = false,
}: WebGLStageOptions) {
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const createRef = React.useRef(create);
  React.useInsertionEffect(() => {
    createRef.current = create;
  });

  React.useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas || !enabled) return;
    if (!supportsWebGL()) {
      const timer = window.setTimeout(() => setFailed(true), 0);
      return () => window.clearTimeout(timer);
    }

    let disposed = false;
    let frame = 0;
    let previous = performance.now();
    let contextAlive = true;
    let lossTimer = 0;
    let onScreen = true;

    const renderer = new THREE.WebGLRenderer({ canvas, antialias, alpha, stencil, powerPreference: "high-performance" });
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, maxDpr));

    let handle: WebGLStageHandle = {};
    const resize = () => {
      const width = Math.max(1, stage.clientWidth);
      const height = Math.max(1, stage.clientHeight);
      const extraCap = handle.getDpr?.(width, height) ?? Number.POSITIVE_INFINITY;
      renderer.setPixelRatio(Math.max(0.5, Math.min(window.devicePixelRatio || 1, maxDpr, extraCap)));
      renderer.setSize(width, height, false);
      handle.onResize?.(width, height);
    };
    const context: WebGLStageContext = {
      renderer,
      stage,
      canvas,
      markReady: () => {
        if (!disposed) setReady(true);
      },
      markFailed: () => {
        if (!disposed) setFailed(true);
      },
      isDisposed: () => disposed,
      requestResize: () => {
        if (!disposed) resize();
      },
    };
    handle = createRef.current(context) ?? {};
    const resizeObserver = new ResizeObserver(resize);
    resizeObserver.observe(stage);

    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
      },
      { rootMargin },
    );
    intersectionObserver.observe(stage);

    // preventDefault opts into restoration; Three re-uploads retained resources
    // on the next render after the context returns. Only a loss that never
    // restores becomes a visible failure.
    const contextLost = (event: Event) => {
      event.preventDefault();
      contextAlive = false;
      window.clearTimeout(lossTimer);
      lossTimer = window.setTimeout(() => {
        if (!disposed && !contextAlive) setFailed(true);
      }, 2500);
    };
    const contextRestored = () => {
      window.clearTimeout(lossTimer);
      contextAlive = true;
      if (disposed) return;
      setFailed(false);
      resize();
    };
    canvas.addEventListener("webglcontextlost", contextLost);
    canvas.addEventListener("webglcontextrestored", contextRestored);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      if (contextAlive && onScreen && document.visibilityState === "visible") {
        handle.onFrame?.(delta, time);
      }
      frame = requestAnimationFrame(render);
    };

    resize();
    frame = requestAnimationFrame(render);

    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      window.clearTimeout(lossTimer);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      canvas.removeEventListener("webglcontextlost", contextLost);
      canvas.removeEventListener("webglcontextrestored", contextRestored);
      handle.dispose?.();
      renderer.dispose();
    };
  }, [alpha, antialias, canvasRef, enabled, maxDpr, rootMargin, signature, stageRef, stencil]);

  return { ready, failed };
}
